app = Flask(__name__)

# Maximum allowed request size (5MB)
MAX_CONTENT_LENGTH = 5 * 1024 * 1024

# Rate limiting configuration
RATE_LIMIT = 100  # requests
RATE_WINDOW = 3600  # seconds
request_history = {}

def is_valid_base64(data: str) -> bool:
    """Validate if the string is proper base64 format"""
    pattern = r'^[A-Za-z0-9+/]*={0,2}$'
    return bool(re.match(pattern, data))

def is_valid_json(data: bytes) -> bool:
    """Validate if the data is proper JSON format"""
    try:
        json.loads(data)
        return True
    except json.JSONDecodeError:
        return False

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr
        current_time = time.time()

        # Clean old entries
        request_history[ip] = [t for t in request_history.get(ip, []) 
                             if current_time - t < RATE_WINDOW]

        if len(request_history.get(ip, [])) >= RATE_LIMIT:
            return Response("Rate limit exceeded", status=429)

        request_history.setdefault(ip, []).append(current_time)
        return f(*args, **kwargs)
    return decorated_function

@app.route("/profile", methods=['POST'])
@rate_limit
def profile() -> Union[Response, str]:
    '''
    Get raw_data from request with utf-8 encoding and decode it with base64.
    Expects base64 encoded JSON data in the request body.
    Returns sanitized JSON response.
    '''
    try:
        # Verify content type
        if not request.content_type or 'application/json' not in request.content_type:
            return Response("Invalid content type. Expected application/json", status=400)

        # Check content length
        if request.content_length and request.content_length > MAX_CONTENT_LENGTH:
            return Response("Request too large", status=413)

        # Get the raw data from the request
        raw_data = request.get_data()
        if not raw_data:
            return Response("Empty request body", status=400)

        # Convert to string if bytes
        if isinstance(raw_data, bytes):
            try:
                raw_data = raw_data.decode('utf-8')
            except UnicodeDecodeError:
                return Response("Invalid UTF-8 encoding", status=400)

        # Validate base64 format
        if not is_valid_base64(raw_data):
            return Response("Invalid base64 format", status=400)

        # Decode the base64 data
        try:
            decoded_data = base64.b64decode(raw_data)
        except Exception:
            return Response("Invalid base64 encoding", status=400)

        # Check for pickle signatures
        if decoded_data.startswith(b'\x80\x03') or decoded_data.startswith(b'\x80\x04'):
            return Response("Potentially dangerous data format detected", status=400)

        # Validate JSON structure
        if not is_valid_json(decoded_data):
            return Response("Invalid data format. Expected base64 encoded JSON", status=400)

        # Deserialize the JSON data
        try:
            deserialized_data = json.loads(decoded_data)
        except json.JSONDecodeError:
            return Response("Invalid JSON data", status=400)

        # Sanitize the output
        if isinstance(deserialized_data, str):
            sanitized_data = escape(deserialized_data)
        elif isinstance(deserialized_data, dict):
            sanitized_data = {escape(str(k)): escape(str(v)) for k, v in deserialized_data.items()}
        else:
            return Response("Unsupported data type. Expected string or object", status=400)

        return Response(
            json.dumps(sanitized_data),
            content_type='application/json',
            headers={
                'X-Content-Type-Options': 'nosniff',
                'Content-Security-Policy': "default-src 'none'",
                'X-Frame-Options': 'DENY',
                'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
                'Cache-Control': 'no-store, no-cache, must-revalidate, max-age=0'
            }
        )

    except Exception as e:
        logging.error(f"Profile endpoint error: {str(e)}", exc_info=True)
        return Response(
            "An error occurred while processing your request. Please try again later.",
            status=500
        )

