from flask import Flask, redirect, request
from urllib.parse import urlparse
import os
import logging
import re

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Constants
MAX_URL_LENGTH = 2048
MAX_LOG_LENGTH = 500
ALLOWED_DOMAINS = {
    'example.com',
    'trusted-domain.com',
    'safe-site.org'
}

class URLValidator:
    @staticmethod
    def sanitize_log_input(text):
        """Sanitize input for logging with enhanced security"""
        if not text:
            return ''
        sanitized = re.sub(r'[\x00-\x1F\x7F-\x9F]', '', str(text))
        sanitized = sanitized.replace('\n', '').replace('\r', '')
        sanitized = (sanitized
                    .replace('&', '&amp;')
                    .replace('<', '&lt;')
                    .replace('>', '&gt;'))
        return sanitized[:MAX_LOG_LENGTH]

    @staticmethod
    def is_safe_url(url):
        """Enhanced URL validation with strict security checks"""
        try:
            if not url or not isinstance(url, str) or len(url) > MAX_URL_LENGTH:
                return False

            parsed = urlparse(url)

            if not parsed.scheme or not parsed.netloc:
                return False
            if parsed.scheme not in {'http', 'https'}:
                return False

            domain = parsed.netloc.lower()
            if '@' in domain or ':' in domain:
                return False

            if domain.startswith('www.'):
                domain = domain[4:]

            if domain not in ALLOWED_DOMAINS:
                return False

            if parsed.fragment or not parsed.path:
                return False

            path = parsed.path.lower()
            dangerous_patterns = {'..', './/', '/./', '//', '\\'}
            if any(pattern in path for pattern in dangerous_patterns):
                return False

            if parsed.query:
                query_pairs = parsed.query.split('&')
                if any('=' not in pair for pair in query_pairs):
                    return False

            return True

        except Exception as e:
            logger.error(f"URL validation error: {URLValidator.sanitize_log_input(str(e))}")
            return False

def create_app():
    """Factory function to create the Flask application"""
    app = Flask(__name__)

    @app.route('/health')
    def health_check():
        """Basic health check endpoint"""
        return {'status': 'healthy'}, 200

    @app.route('/redirect')
    def redirect_to_target():
        """Secure redirect handler with enhanced validation"""
        target_url = request.args.get('url', '')

        if not target_url:
            logger.warning("Redirect attempt with no URL provided")
            return "No target URL provided", 400

        sanitized_url = URLValidator.sanitize_log_input(target_url)

        if not URLValidator.is_safe_url(target_url):
            logger.warning(f"Rejected redirect attempt to: {sanitized_url}")
            return "Redirect not allowed for this URL", 403

        logger.info(f"Redirecting to validated URL: {sanitized_url}")
        return redirect(target_url)

    return app

if __name__ == '__main__':
    app = create_app()
    host = os.environ.get('FLASK_HOST', '127.0.0.1')
    port = int(os.environ.get('FLASK_PORT', 5000))
    debug = os.environ.get('FLASK_ENV') == 'development'

    app.run(
        host=host,
        port=port,
        debug=debug
    )

import os
import sys
import logging
from flask import Flask, redirect, request, abort
from urllib.parse import urlparse
import re
from typing import List, Optional, Dict, Any
from logging.handlers import RotatingFileHandler
import html

# Configure logging with more secure settings
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        RotatingFileHandler('app.log', maxBytes=1000000, backupCount=3)
    ]
)
logger = logging.getLogger(__name__)

# Enhanced configuration constants
DEFAULT_ALLOWED_DOMAINS: List[str] = ['example.com', 'trusted-domain.com']
DEFAULT_HOST: str = '127.0.0.1'
DEFAULT_PORT: int = 5000
MAX_URL_LENGTH: int = 2048
MAX_LOG_FIELD_LENGTH: int = 1000

def sanitize_log_input(input_data: Any) -> str:
    """Enhanced sanitization for log inputs"""
    if input_data is None:
        return 'None'

    # Convert to string and limit length
    sanitized = str(input_data)[:MAX_LOG_FIELD_LENGTH]
    # HTML escape special characters
    sanitized = html.escape(sanitized)
    # Remove control characters and non-printable characters
    sanitized = ''.join(char for char in sanitized if char.isprintable())
    # Additional escaping for log-specific characters
    sanitized = sanitized.replace('%', '%%')
    sanitized = sanitized.replace('{', '{{').replace('}', '}}')
    return sanitized

def is_valid_domain(url: Optional[str]) -> bool:
    """Enhanced URL validation with additional security checks"""
    try:
        if not url or len(url) > MAX_URL_LENGTH:
            return False

        if not url.startswith('https://'):
            return False

        parsed = urlparse(url)

        # Strict scheme validation
        if not all([parsed.scheme, parsed.netloc]) or parsed.scheme != 'https':
            return False

        # Enhanced domain pattern with strict validation
        domain_pattern = r'^(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+[a-zA-Z]{2,63}$'
        if not re.match(domain_pattern, parsed.netloc, re.IGNORECASE):
            return False

        # Comprehensive path validation
        if any(char in parsed.path for char in '<>"\'%;{}`'):
            return False

        if '..' in parsed.path or '//' in parsed.path:
            return False

        # Query parameter validation
        if parsed.query:
            if any(char in parsed.query for char in '<>"\'%;{}'):
                return False

        return True
    except Exception as e:
        logger.error("URL validation error", extra={
            'error_type': sanitize_log_input(type(e).__name__),
            'error_message': sanitize_log_input(str(e)),
            'url': sanitize_log_input(url)
        })
        return False

def validate_config(config: Dict[str, Any]) -> Dict[str, Any]:
    """Enhanced configuration validation"""
    if not config.get('ALLOWED_DOMAINS'):
        config['ALLOWED_DOMAINS'] = DEFAULT_ALLOWED_DOMAINS

    if not isinstance(config['ALLOWED_DOMAINS'], list):
        raise ValueError("ALLOWED_DOMAINS must be a list")

    # Strict domain validation
    domain_pattern = r'^(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+[a-zA-Z]{2,63}$'
    for domain in config['ALLOWED_DOMAINS']:
        if not isinstance(domain, str) or not re.match(domain_pattern, domain):
            raise ValueError(f"Invalid domain in ALLOWED_DOMAINS: {sanitize_log_input(domain)}")

    return config

def create_app(test_config: Optional[Dict[str, Any]] = None) -> Flask:
    """Secure application factory with enhanced error handling"""
    app = Flask(__name__)

    if test_config is None:
        app.config.from_pyfile('config.py', silent=True)
    else:
        app.config.update(test_config)

    app.config = validate_config(app.config)

    @app.route('/redirect')
    def redirect_to_target():
        """Enhanced secure redirect handler"""
        try:
            target_url = request.args.get('url')

            if not target_url:
                logger.warning("Missing target URL")
                return abort(400, description="No target URL provided")

            if not is_valid_domain(target_url):
                logger.warning("Invalid URL format", extra={
                    'url': sanitize_log_input(target_url)
                })
                return abort(400, description="Invalid target URL")

            parsed_url = urlparse(target_url)
            if parsed_url.netloc not in app.config['ALLOWED_DOMAINS']:
                logger.warning("Unauthorized domain access attempt", extra={
                    'domain': sanitize_log_input(parsed_url.netloc)
                })
                return abort(403, description="Domain not allowed")

            logger.info("Successful redirect", extra={
                'target': sanitize_log_input(target_url)
            })
            return redirect(target_url, code=302)

        except Exception as e:
            logger.error("Redirect processing error", extra={
                'error_type': sanitize_log_input(type(e).__name__),
                'error_message': sanitize_log_input(str(e))
            })
            return abort(500, description="Internal server error")

    return app

def init_app() -> Flask:
    """Enhanced application initialization with error handling"""
    try:
        app = create_app()
        return app
    except Exception as e:
        logger.critical("Fatal application initialization error", extra={
            'error_type': sanitize_log_input(type(e).__name__),
            'error_message': sanitize_log_input(str(e))
        })
        sys.exit(1)

if __name__ == '__main__':
    app = init_app()
    host = os.environ.get('HOST', DEFAULT_HOST)
    port = int(os.environ.get('PORT', DEFAULT_PORT))

    app.run(
        host=host,
        port=port,
        debug=False,
        ssl_context='adhoc'  # Enforce HTTPS
    )

