    def is_safe_path(base_dir: str, path: str, depth_limit: int = MAX_PATH_DEPTH) -> bool:
        try:
            # Resolve any symbolic links
            base_abs = os.path.realpath(os.path.abspath(base_dir))
            path_abs = os.path.realpath(os.path.abspath(path))

            # Check if path is within base directory
            if not path_abs.startswith(base_abs):
                return False

            # Check path depth
            relative_path = os.path.relpath(path_abs, base_abs)
            if relative_path.count(os.sep) > depth_limit or '..' in relative_path:
                return False

            return True
        except Exception:
            return False

    @staticmethod
    def sanitize_filename(filename: str) -> str:
        """Enhanced filename sanitization"""
        # Remove any directory traversal attempts
        filename = os.path.basename(filename)
        # Only allow specific characters
        return ''.join(c for c in filename if c.isalnum() or c in '._-')

class PathConfiguration:
    @staticmethod
    def get_base_directory() -> str:
        """Get and validate base directory"""
        if base_dir := os.getenv('APP_BASE_DIR'):
            base_dir = os.path.realpath(os.path.abspath(base_dir))
        else:
            try:
                base_dir = os.path.realpath(os.path.dirname(__file__))
            except NameError:
                base_dir = os.path.realpath(os.getcwd())

        return base_dir

    @staticmethod
    def ensure_directory(directory: str) -> bool:
        """Ensure directory exists and is accessible with enhanced security"""
        try:
            directory = os.path.realpath(directory)
            os.makedirs(directory, exist_ok=True)
            test_file = os.path.join(directory, '.test')
            with open(test_file, 'w') as f:
                f.write('test')
            os.remove(test_file)
            return True
        except Exception as e:
            logger.error(f"Directory access error: {e}")
            return False

# Initialize base directory
BASE_DIR = PathConfiguration.get_base_directory()

class FileHandler:
    """Enhanced file handling with additional security measures"""
    @staticmethod
    def validate_and_get_file(filename: Optional[str], base_dir: str) -> Tuple[bool, str, Optional[str]]:
        if not filename or not isinstance(filename, str):
            return False, "Invalid filename", None

        # Enhanced sanitization
        clean_filename = PathValidator.sanitize_filename(filename)
        if not clean_filename:
            return False, "Invalid filename characters", None

        # Strict extension validation
        if Path(clean_filename).suffix.lower() not in ALLOWED_EXTENSIONS:
            return False, "Invalid file extension", None

        file_path = os.path.join(base_dir, clean_filename)
        file_path = os.path.realpath(file_path)

        # Enhanced path security validation
        if not PathValidator.is_safe_path(base_dir, file_path):
            return False, "Invalid file path", None

        try:
            if not os.path.isfile(file_path):
                return False, "File not found", None

            with open(file_path, 'r') as f:
                content = f.read()
            return True, "Success", content
        except Exception as e:
            logger.error(f"File reading error: {e}")
            return False, "File access error", None

@app.route("/filedata")
def get_file_data():
    """Enhanced API endpoint with additional security"""
    filename = request.args.get('filename')

    success, message, content = FileHandler.validate_and_get_file(filename, BASE_DIR)
    if not success:
        return jsonify({'error': message}), 400

    return jsonify({
        'filename': filename,
        'content': content
    }), 200

def initialize_app():
    """Enhanced application initialization with security checks"""
    if not PathConfiguration.ensure_directory(BASE_DIR):
        logger.error("Failed to initialize base directory")
        return False

    if not SecurityConfig.validate_host(HOST):
        logger.error("Invalid host configuration")
        return False

    return True

if __name__ == '__main__':
    sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

    if not initialize_app():
        sys.exit(1)

    app.run(debug=False, host=HOST, port=PORT)

