    }
})

app = Flask(__name__)
app.config['TESTING'] = True

def safe_log(message: str, data: Dict[str, Any]) -> None:
    """Safely log messages with comprehensive sanitization"""
    sanitized_data = {}
    for k, v in data.items():
        if isinstance(v, str):
            sanitized_value = ''.join(char if char.isprintable() else f'\\x{ord(char):02x}'
                                    for char in str(v))
            sanitized_data[k] = sanitized_value
        else:
            sanitized_data[k] = str(v)
    app.logger.info(message, extra={'data': sanitized_data})

def validate_input(value: str, pattern: str, max_length: int = 64) -> bool:
    """Validate input against allowed patterns with length restriction"""
    if not value or len(value) > max_length:
        return False
    return bool(re.match(pattern, value))

def sanitize_ldap_string(value: str) -> str:
    """Comprehensive LDAP string sanitization"""
    return ldap.filter.escape_filter_chars(value)

def create_safe_filter(username: str) -> str:
    """Create a safe LDAP filter with proper encoding"""
    safe_username = sanitize_ldap_string(username)
    return f"(&(objectClass=person)(uid={safe_username}))"

def create_safe_dn(dc: str) -> str:
    """Create a safe Distinguished Name"""
    safe_dc = sanitize_ldap_string(dc)
    return f"dc={safe_dc},dc=com"

def sanitize_response(data: Dict[str, Any]) -> Dict[str, Any]:
    """Sanitize response data to prevent XSS"""
    if isinstance(data, dict):
        return {k: html.escape(str(v)) if isinstance(v, str) else v 
                for k, v in data.items()}
    return data

@app.route("/normal")
def normal() -> Union[Dict[str, Any], tuple]:
    """Handle LDAP user lookup with enhanced security"""
    with app.app_context():
        try:
            # Get and validate parameters
            dc = request.args.get('dc', '')
            username = request.args.get('username', '')

            # Log sanitized input
            safe_log("Received request", {'dc': dc, 'username': username})

            # Stricter input validation
            if not validate_input(dc, r'^[a-zA-Z0-9][-a-zA-Z0-9]*$', 32):
                return {"error": "Invalid domain component format"}, 400

            if not validate_input(username, r'^[a-zA-Z0-9][-a-zA-Z0-9._]*$', 64):
                return {"error": "Invalid username format"}, 400

            # Create safe LDAP queries
            base_dn = create_safe_dn(dc)
            search_filter = create_safe_filter(username)

            # LDAP connection configuration
            ldap_config = {
                'uri': 'ldap://localhost:389',
                'timeout': 10,
                'network_timeout': 5
            }

            ldap_conn = ldap.initialize(ldap_config['uri'])
            ldap_conn.set_option(ldap.OPT_TIMEOUT, ldap_config['timeout'])
            ldap_conn.set_option(ldap.OPT_NETWORK_TIMEOUT, ldap_config['network_timeout'])
            ldap_conn.set_option(ldap.OPT_REFERRALS, 0)  # Disable referrals for security

            attrs = ['uid', 'cn', 'mail']

            try:
                result = ldap_conn.search_s(
                    base_dn,
                    ldap.SCOPE_SUBTREE,
                    search_filter,
                    attrs
                )
            finally:
                ldap_conn.unbind_s()

            if not result:
                safe_log("User not found", {'username': username})
                return {"error": "User not found"}, 404

            # Process and sanitize results
            dn, entry = result[0]
            response = {}

            for key, value in entry.items():
                if isinstance(value, list) and len(value) == 1:
                    try:
                        response[key] = value[0].decode('utf-8') if isinstance(value[0], bytes) else value[0]
                    except UnicodeDecodeError:
                        response[key] = str(value[0])
                else:
                    response[key] = value

            safe_log("Request processed successfully", {'username': username})
            return sanitize_response(response)

        except ldap.LDAPError as e:
            app.logger.error("LDAP Error", exc_info=True)
            return {"error": "Internal server error"}, 500
        except Exception as e:
            app.logger.error("Unexpected error", exc_info=True)
            return {"error": "Internal server error"}, 500

