    fs_helper = FileSystemHelper()
except Exception as e:
    logger.error(f"Failed to initialize FileSystemHelper: {str(e)}")
    raise

def sanitize_log_message(message: str) -> str:
    """Sanitize log messages by removing special characters and limiting length."""
    if not message:
        return ''
    sanitized = html.escape(str(message))
    sanitized = re.sub(r'[^\w\-\.\s\/]', '', sanitized)
    return sanitized[:MAX_LOG_LENGTH]

def is_safe_path(path: Path) -> bool:
    """Additional safety checks for file path."""
    try:
        if fs_helper.is_symlink(path):
            return False
        allowed_dir = fs_helper.get_allowed_directory()
        if not path.is_relative_to(allowed_dir):
            return False
        if len(str(path)) > MAX_PATH_LENGTH:
            return False
        return True
    except Exception:
        return False

def validate_file_path(file_path: str) -> Optional[Path]:
    """Validate and sanitize the file path."""
    if not file_path:
        raise ValueError("No file path provided")

    try:
        sanitized_path = re.sub(r'[^\w\-\.\s\/]', '', file_path)
        safe_path = (fs_helper.get_allowed_directory() / sanitized_path).resolve()

        if not is_safe_path(safe_path):
            raise ValueError("Invalid path")

        if safe_path.suffix.lower() not in ALLOWED_EXTENSIONS:
            raise ValueError("File type not allowed")

        return safe_path
    except Exception as e:
        raise ValueError(f"Invalid path: {str(e)}")

@app.route('/download')
def download():
    """Handle file download requests."""
    try:
        file_path = request.args.get('file', '')
        logger.info("Download requested for file: %s", 
                   sanitize_log_message(file_path))

        safe_path = validate_file_path(file_path)

        if not fs_helper.is_file(safe_path):
            logger.warning("File not found: %s", 
                         sanitize_log_message(str(safe_path)))
            return "File not found", 404

        filename = safe_path.name

        return send_file(
            str(safe_path),
            as_attachment=True,
            download_name=filename,
            mimetype='application/octet-stream'
        )

    except ValueError as e:
        logger.warning("Validation error: %s", 
                      sanitize_log_message(str(e)))
        return "Invalid request", 400
    except Exception as e:
        logger.error("Unexpected error: %s", 
                    sanitize_log_message(str(e)))
        return "Internal server error", 500

if __name__ == '__main__':
    host = os.getenv('HOST', '127.0.0.1')
    port = int(os.getenv('PORT', 5000))

    try:
        allowed_dir = fs_helper.get_allowed_directory()
        if not fs_helper.is_dir(allowed_dir):
            raise RuntimeError(f"Allowed directory does not exist: {allowed_dir}")

        if not fs_helper.has_read_access(allowed_dir):
            raise RuntimeError(f"Allowed directory is not readable: {allowed_dir}")

        logger.info(f"Starting server with base directory: {allowed_dir}")
        app.run(host=host, port=port)
    except Exception as e:
        logger.error(f"Failed to start server: {str(e)}")
        raise

import os
import logging
from flask import Response, request, Flask
import re
import tempfile
from pathlib import Path
from typing import List, Optional, Dict
from functools import wraps
import secrets
from werkzeug.security import safe_join

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# Configuration
BASE_DIR = Path(os.getenv('USER_FILES_BASE_DIR', tempfile.gettempdir())).resolve()
MAX_FILES_TO_LIST = 100  # Reduced from 1000 for better pagination
PAGE_SIZE = 50
ALLOWED_CHARS = re.compile('^[a-zA-Z0-9_-]{3,32}$')  # Strengthened regex
REQUEST_COUNTER: Dict[str, int] = {}
RATE_LIMIT = 100  # requests per minute

class SecurityError(Exception):
    """Custom exception for security-related issues"""
    pass

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr
        REQUEST_COUNTER[ip] = REQUEST_COUNTER.get(ip, 0) + 1
        if REQUEST_COUNTER[ip] > RATE_LIMIT:
            logger.warning(f"Rate limit exceeded for IP: {ip}")
            return Response("Too many requests", status=429)
        return f(*args, **kwargs)
    return decorated_function

def sanitize_path_component(component: str) -> str:
    """Sanitize individual path components"""
    return re.sub(r'[^a-zA-Z0-9_-]', '', component)

def is_safe_username(username: str) -> bool:
    """Validate username with strengthened criteria"""
    if not username:
        return False
    return bool(ALLOWED_CHARS.match(username))

def get_secure_path(base: Path, *paths: str) -> Optional[Path]:
    """Securely join paths and verify they're within base directory"""
    try:
        # Use werkzeug's safe_join for initial path joining
        joined = safe_join(str(base), *[sanitize_path_component(p) for p in paths])
        if not joined:
            return None

        path = Path(joined).resolve()
        base_resolved = base.resolve()

        # Verify the path is within base directory
        if base_resolved in path.parents or path == base_resolved:
            return path
        return None
    except Exception as e:
        logger.error(f"Path validation error: {str(e)}")
        return None

def ensure_user_directory(username: str) -> Path:
    """Ensure user directory exists with proper permissions"""
    if not is_safe_username(username):
        raise SecurityError("Invalid username format")

    user_path = get_secure_path(BASE_DIR, username)
    if not user_path:
        raise SecurityError("Invalid path")

    try:
        # Create directory with secure permissions
        user_path.mkdir(mode=0o700, parents=True, exist_ok=True)
        return user_path
    except Exception as e:
        logger.error(f"Directory creation error: {type(e).__name__}")
        raise SecurityError("Unable to access user directory")

def list_user_files(path: Path, page: int = 0) -> List[str]:
    """Safely list files with pagination"""
    try:
        if not path.is_dir():
            raise SecurityError("Invalid directory")

        files = []
        start_idx = page * PAGE_SIZE
        end_idx = start_idx + PAGE_SIZE

        # Use scandir for better performance
        with os.scandir(str(path)) as entries:
            files = [entry.name for entry in entries if entry.is_file()]

        files.sort()
        return files[start_idx:end_idx]
    except Exception as e:
        logger.error(f"File listing error: {type(e).__name__}")
        raise SecurityError("Unable to list files")

@app.route('/reply')
@rate_limit
def listFiles():
    """List files in user's directory with enhanced security controls"""
    try:
        username = request.args.get('username')
        page = int(request.args.get('page', '0'))

        if not username:
            return Response("Username parameter is required", status=400)

        if not is_safe_username(username):
            return Response("Invalid username format", status=400)

        if page < 0:
            return Response("Invalid page number", status=400)

        user_path = ensure_user_directory(username)
        files = list_user_files(user_path, page)

        response = Response("\n".join(files), mimetype='text/plain')
        response.headers['X-Content-Type-Options'] = 'nosniff'
        response.headers['X-Frame-Options'] = 'DENY'
        return response

    except SecurityError as se:
        logger.warning(f"Security violation attempt: {type(se).__name__}")
        return Response("Invalid request", status=400)
    except Exception as e:
        logger.error(f"Unexpected error: {type(e).__name__}")
        return Response("Internal server error", status=500)

if __name__ == '__main__':
    try:
        # Ensure base directory exists with proper permissions
        BASE_DIR.mkdir(mode=0o755, parents=True, exist_ok=True)
        # Generate secret key for session management
        app.secret_key = secrets.token_hex(32)
        # Bind only to localhost with additional security settings
        app.run(host='127.0.0.1', port=5000, ssl_context='adhoc')
    except Exception as e:
        logger.critical(f"Failed to initialize application: {type(e).__name__}")
        exit(1)

from flask import Flask, current_app
from flask import request
import html
