)

class TestingConfig:
    """Testing configuration"""
    TESTING = True
    DEBUG = True
    SECRET_KEY = 'test_key'

def create_app(config_object=None):
    """Enhanced application factory function"""
    app = Flask(__name__)

    # Default configuration
    app.config.from_mapping(
        SECRET_KEY='dev',
        DEBUG=True
    )

    if config_object is not None:
        if isinstance(config_object, dict):
            app.config.update(config_object)
        else:
            app.config.from_object(config_object)

    return app

@contextmanager
def app_context(app):
    """Context manager for app context"""
    ctx = app.app_context()
    ctx.push()
    try:
        yield
    finally:
        ctx.pop()

def sanitize_log_input(input_string: str, max_length: int = 200) -> str:
    """Sanitize input for logging by removing special characters and limiting length"""
    if not isinstance(input_string, str):
        return "invalid_input"

    try:
        # Truncate long input
        input_string = input_string[:max_length]

        # Remove special characters, control characters, and potentially harmful characters
        sanitized = re.sub(r'[^\w\s\-.,]', '', input_string)
        return sanitized
    except Exception as e:
        logging.error(f"Error in sanitize_log_input: {str(e)}")
        return "sanitization_failed"

def sanitize_structured_data(data: Any) -> Any:
    """Sanitize structured data for logging"""
    try:
        if isinstance(data, dict):
            return {sanitize_log_input(str(k)): sanitize_structured_data(v) 
                    for k, v in data.items()}
        elif isinstance(data, (list, tuple)):
            return [sanitize_structured_data(item) for item in data]
        elif isinstance(data, (int, float)):
            return data
        else:
            return sanitize_log_input(str(data))
    except Exception as e:
        logging.error(f"Error in sanitize_structured_data: {str(e)}")
        return "structured_sanitization_failed"

def structured_log_message(message_type: str, data: Dict[str, Any]) -> str:
    """Create a structured log message with sanitized input"""
    try:
        sanitized_data = {
            'type': sanitize_log_input(message_type),
            'data': sanitize_structured_data(data)
        }
        return json.dumps(sanitized_data)
    except Exception as e:
        logging.error(f"Error in structured_log_message: {str(e)}")
        return json.dumps({'type': 'error', 'data': str(e)})

def init_app():
    """Initialize the application for testing"""
    app = create_app(TestingConfig)

    @app.route('/logger')
    def logger():
        try:
            name = request.args.get('name', 'no name provided')
            log_data = structured_log_message('name_received', {'name': name})
            logging.info('%s', log_data)
            safe_display_name = html.escape(name)
            return f'Logged name: {safe_display_name}'
        except Exception as e:
            error_details = structured_log_message('error', {
                'error_type': type(e).__name__,
                'error_message': str(e)
            })
            logging.error('%s', error_details)
            return 'An error occurred processing your request', 500

    return app

if __name__ == '__main__':
    app = init_app()
    app.run(host='127.0.0.1', port=5000)

