            return {'error': 'No file selected'}, 400

        # Validate filename
        secure_fname = secure_filename(file.filename)
        if not validate_filename(secure_fname) or not allowed_file(secure_fname):
            return {'error': 'Invalid filename'}, 400

        # Safely search for username in filename
        try:
            sanitized_username = re.escape(username)
            sanitized_filename = escape(secure_fname)

            if re.search(sanitized_username, secure_fname, re.IGNORECASE):
                return {
                    'message': 'Username found in filename',
                    'username': escape(username),
                    'filename': sanitized_filename
                }, 200
            else:
                return {
                    'message': 'Username not found in filename',
                    'username': escape(username),
                    'filename': sanitized_filename
                }, 404
        except Exception as e:
            logger.error(f"String processing error: {str(e)}")
            return {'error': 'Error processing strings'}, 500

    except Exception as e:
        logger.error(f"Error in upload endpoint: {str(e)}")
        return {'error': 'An internal error occurred'}, 500

