def dataSorting():
    '''
    Continuously take (basename,data) key-value pair from foo() function and sort it
    '''
    # Create a dictionary to store the key-value pairs
    data_dict = {}

    try:
        while True:
            # Get the key-value pair from foo()
            basename, data = foo()

            # Store in dictionary
            if basename in data_dict:
                if isinstance(data_dict[basename], list):
                    data_dict[basename].append(data)
                else:
                    data_dict[basename] = [data_dict[basename], data]
            else:
                data_dict[basename] = data

            # Sort the values if they are in a list
            if isinstance(data_dict[basename], list):
                data_dict[basename].sort()

    except KeyboardInterrupt:
        # Allow graceful exit with Ctrl+C
        pass

    # Return the sorted dictionary
    return dict(sorted(data_dict.items()))

