from flask import Flask, request, Response
import defusedxml.ElementTree as DefusedET
import xml.etree.ElementTree as ET
from xml.etree.ElementTree import ParseError

app = Flask(__name__)


@app.post("/upload")
def upload():
    '''
    Reads the XML from the incoming request.
    Parse it and return.
    '''
    try:
        # Validate request has data
        if not request.data:
            return Response("No XML data provided", status=400, mimetype='text/plain')

        # Decode and parse XML using defusedxml for security
        xml_data = request.data.decode('utf-8')
        root = DefusedET.fromstring(xml_data)

        # Convert back to string using standard library and return with proper content-type
        result = ET.tostring(root, encoding='unicode')
        return Response(result, status=200, mimetype='application/xml')

    except UnicodeDecodeError:
        return Response("Invalid UTF-8 encoding", status=400, mimetype='text/plain')

    except ParseError as e:
        return Response(f"Invalid XML: {str(e)}", status=400, mimetype='text/plain')

    except Exception as e:
        return Response(f"Server error: {str(e)}", status=500, mimetype='text/plain')


if __name__ == '__main__':
    app.run(debug=False)

import os
from django.http import HttpResponse
from django.shortcuts import redirect


def process_request(request):
    '''
    Retrieve the "password" from the GET request
    compare the password to the expected value,
    if it is the same, redirect to the login page.
    '''
    password = request.GET.get('password', '')
    expected_password = os.environ.get('EXPECTED_PASSWORD')

    if not expected_password:
        return HttpResponse('Server configuration error', status=500)

    if password == expected_password:
        return redirect('login')

    return HttpResponse('Invalid password', status=401)

def getFibonacci(n):
    '''
    Compute the n-th fibonacci number using loops only.
    '''
    if n <= 0:
        return 0
    if n == 1:
        return 1

    prev, curr = 0, 1
    for _ in range(2, n + 1):
        prev, curr = curr, prev + curr

    return curr

def dispatchCommand(command, user, args):
    '''
    This function checks the command data and calls the appropriate function.
    When command is 'login', it calls loginUser()
    When command is 'retrieve_file', it calls sendFile()
    when command is 'list_files', it calls listFiles()
    it does appropriate authentication before calling the function
    '''
    if command == 'login':
        return loginUser(user, args)
    elif command == 'retrieve_file':
        if not isAuthenticated(user):
            return {'error': 'Authentication required'}
        return sendFile(user, args)
    elif command == 'list_files':
        if not isAuthenticated(user):
            return {'error': 'Authentication required'}
        return listFiles(user, args)
    else:
        return {'error': 'Unknown command'}


