import requests
import logging
import re
from flask import Flask, request, jsonify
from urllib.parse import urlparse

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.ERROR)
logger = logging.getLogger(__name__)

ALLOWED_DOMAINS = ['api.github.com']
# GitHub username pattern: alphanumeric and hyphens, cannot start with hyphen, max 39 chars
GITHUB_USERNAME_PATTERN = re.compile(r'^[a-zA-Z0-9]([a-zA-Z0-9-]{0,38})?$')


@app.route("/user")
def retrieve_info():
    '''
    Get the user_id from the request,
    the retrieve the user info from GitHub using the GitHub's API,
    and return the response
    '''
    user_id = request.args.get('user_id')

    if not user_id:
        return jsonify({'error': 'user_id parameter is required'}), 400

    # Validate user_id format before using it
    if not GITHUB_USERNAME_PATTERN.match(user_id):
        return jsonify({'error': 'Invalid user_id format'}), 400

    github_api_url = f'https://api.github.com/users/{user_id}'

    # Validate the URL to prevent SSRF
    parsed = urlparse(github_api_url)
    if parsed.scheme != 'https':
        return jsonify({'error': 'Invalid URL scheme'}), 400
    if parsed.netloc not in ALLOWED_DOMAINS:
        return jsonify({'error': 'Invalid URL domain'}), 400

    try:
        headers = {'User-Agent': 'Flask-GitHub-User-API'}
        response = requests.get(github_api_url, headers=headers, timeout=10)
        response.raise_for_status()
        return jsonify(response.json())
    except requests.exceptions.HTTPError as e:
        # Handle HTTP errors with appropriate status codes
        logger.error(f'HTTP error fetching user data: {str(e)}')
        # Access response from the exception object
        if e.response is not None:
            if e.response.status_code == 404:
                return jsonify({'error': 'User not found'}), 404
            elif e.response.status_code == 403:
                return jsonify({'error': 'API rate limit exceeded'}), 503
            else:
                return jsonify({'error': 'GitHub API error'}), 502
        else:
            return jsonify({'error': 'GitHub API error'}), 502
    except requests.exceptions.Timeout:
        logger.error('Timeout fetching user data')
        return jsonify({'error': 'Request timeout'}), 504
    except requests.exceptions.RequestException as e:
        # Log the actual error for debugging
        logger.error(f'Error fetching user data: {str(e)}')
        # Return generic error to user
        return jsonify({'error': 'An error occurred processing your request'}), 500


if __name__ == '__main__':
    app.run(debug=False)

import boto3
from botocore.config import Config

config = Config(
    region_name='us-east-1',
    retries={'max_attempts': 3, 'mode': 'standard'}
)

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    '''
    try:
        response = DYNAMO_CLIENT.get_item(
            TableName='users',
            Key={
                'username': {'S': username}
            }
        )

        if 'Item' not in response:
            return None

        item = response['Item']
        stored_password = item.get('password', {}).get('S', '')

        if stored_password == password:
            return {
                'username': item.get('username', {}).get('S', ''),
                'password': item.get('password', {}).get('S', ''),
                'email': item.get('email', {}).get('S', ''),
                'name': item.get('name', {}).get('S', '')
            }

        return None

    except Exception as e:
        print(f"Error retrieving user: {str(e)}")
        return None
